let allLeads=[];let statusChart=null;async function toggleDemoMode(){const isDemo=document.getElementById("demo-mode-toggle").checked;const firmSelect=document.getElementById("demo-firm-select");if(isDemo){firmSelect.classList.remove("d-none")}else{firmSelect.classList.add("d-none")}renderLeads([]);if(isDemo){const firm=firmSelect.value;try{const formData=new FormData;formData.append("firm",firm);await fetch(API_BASE+"/demo/seed",{method:"POST",body:formData});await loadLeads()}catch(e){console.error("Seeding failed",e)}}else{await loadLeads()}}async function loadLeads(){const toggle=document.getElementById("demo-mode-toggle");const isDemo=toggle?toggle.checked:false;try{const response=await fetch(API_BASE+`/leads?demo_mode=${isDemo}`);allLeads=await response.json();updateStats();filterLeads()}catch(error){console.error("Error loading leads:",error)}}function updateStats(){const total=allLeads.length;const highPriority=allLeads.filter(l=>l.status==="High Priority").length;const avgScore=total>0?(allLeads.reduce((acc,curr)=>acc+(curr.score||0),0)/total).toFixed(1):0;document.getElementById("stat-total").innerText=total;document.getElementById("stat-high-priority").innerText=highPriority;document.getElementById("stat-avg-score").innerText=avgScore;const hpPercent=total>0?highPriority/total*100:0;document.getElementById("stat-hp-progress").style.width=`${hpPercent}%`;updateChart(allLeads)}function updateChart(leads){const ctx=document.getElementById("statusChart").getContext("2d");const statusCounts={"High Priority":0,"Requires Review":0,Disqualified:0,New:0};leads.forEach(l=>{if(statusCounts.hasOwnProperty(l.status))statusCounts[l.status]++;else statusCounts["New"]++});const data={labels:Object.keys(statusCounts),datasets:[{data:Object.values(statusCounts),backgroundColor:["#198754","#ffc107","#dc3545","#6c757d"],hoverOffset:4,borderWidth:0}]};if(statusChart){statusChart.data=data;statusChart.update()}else{statusChart=new Chart(ctx,{type:"doughnut",data:data,options:{cutout:"70%",plugins:{legend:{display:true,position:"right",labels:{boxWidth:10,font:{size:10}}},tooltip:{enabled:true}},maintainAspectRatio:false}})}}function renderLeads(leads){const table=document.getElementById("leads-table");const emptyState=document.getElementById("empty-state");table.innerHTML="";if(leads.length===0)emptyState.classList.remove("d-none");else emptyState.classList.add("d-none");leads.forEach(lead=>{const tr=document.createElement("tr");if(lead.status==="High Priority")tr.classList.add("priority-row");tr.innerHTML=`\n            <td class="ps-4 fw-bold">#${lead.id}</td>\n            <td>\n                <div class="fw-bold text-dark">${lead.full_name||"Anonymous"}</div>\n                <div class="small text-muted text-truncate" style="max-width: 250px;">${lead.summary||"No summary yet..."}</div>\n            </td>\n            <td><span class="badge bg-light text-dark border">${lead.source||"Chat"}</span></td>\n            <td><span class="badge ${getStatusBadge(lead.status)}">${lead.status}</span></td>\n            <td><span class="badge ${getSyncBadge(lead.sync_status)}">${lead.sync_status||"Not Synced"}</span></td>\n            <td>\n                <div class="d-flex align-items-center">\n\n                    <span class="me-2 fw-bold" style="width: 30px;">${lead.score}</span>\n                    <div class="progress flex-grow-1" style="height: 6px; min-width: 80px; max-width: 120px;">\n                        <div class="progress-bar ${getScoreColor(lead.score)}" role="progressbar" style="width: ${lead.score}%"></div>\n                    </div>\n                </div>\n            </td>\n            <td>\n                <div class="small text-dark">${new Date(lead.created_at).toLocaleDateString()}</div>\n                <div class="text-muted" style="font-size: 0.75rem;">${new Date(lead.created_at).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}</div>\n            </td>\n            <td class="text-end pe-4">\n                <div class="btn-group">\n                    <button class="btn btn-sm btn-primary px-3 rounded-start-pill dropdown-toggle" type="button" data-bs-toggle="dropdown">\n                        <i class="bi bi-cloud-arrow-up me-1"></i> Sync\n                    </button>\n                    <ul class="dropdown-menu shadow border-0">\n                        <li><a class="dropdown-item small" href="#" onclick="syncToSystem(${lead.id}, 'clio')"><i class="bi bi-box-fill me-2 text-warning"></i> Clio Grow</a></li>\n                        <li><a class="dropdown-item small" href="#" onclick="syncToSystem(${lead.id}, 'mycase')"><i class="bi bi-briefcase-fill me-2 text-primary"></i> MyCase</a></li>\n                        <li><a class="dropdown-item small" href="#" onclick="syncToSystem(${lead.id}, 'filevine')"><i class="bi bi-leaf-fill me-2 text-success"></i> Filevine</a></li>\n                        <li><hr class="dropdown-divider"></li>\n                        <li><a class="dropdown-item small" href="#" onclick="syncToSystem(${lead.id}, 'litify')"><i class="bi bi-cloud-fill me-2 text-info"></i> Litify (Salesforce)</a></li>\n                    </ul>\n                    <button class="btn btn-sm btn-white border shadow-sm px-3 rounded-end-pill" onclick="viewLead(${lead.id})">View Case</button>\n                </div>\n            </td>\n            `;table.appendChild(tr)})}function filterLeads(){const status=document.getElementById("filter-status").value;const minScore=document.getElementById("filter-score").value;const searchTerm=document.getElementById("search-input").value.toLowerCase();let filtered=allLeads;if(status)filtered=filtered.filter(l=>l.status===status);if(minScore)filtered=filtered.filter(l=>(l.score||0)>=parseInt(minScore));if(searchTerm){filtered=filtered.filter(l=>l.full_name&&l.full_name.toLowerCase().includes(searchTerm)||l.summary&&l.summary.toLowerCase().includes(searchTerm)||l.id.toString().includes(searchTerm))}renderLeads(filtered)}function getStatusBadge(status){if(status==="High Priority")return"bg-success";if(status==="Requires Review")return"bg-warning text-dark";if(status==="Disqualified")return"bg-danger";if(status==="Document Analysis")return"bg-info text-dark";return"bg-secondary"}function getSyncBadge(status){if(!status||status==="Not Synced")return"bg-light text-muted border";if(status.includes("Synced"))return"bg-primary";if(status==="Error")return"bg-danger";return"bg-secondary"}function getScoreColor(score){if(score>=80)return"bg-success";if(score>=50)return"bg-warning";return"bg-danger"}async function viewLead(id){try{const response=await fetch(API_BASE+`/leads/${id}`);const lead=await response.json();document.getElementById("modal-lead-id").value=lead.id;document.getElementById("modal-name").innerText=lead.full_name||`Lead #${lead.id}`;document.getElementById("modal-summary").innerText=lead.summary||"No summary available.";document.getElementById("modal-transcript").innerHTML=lead.messages.map(m=>`\n            <div class="mb-3 d-flex flex-column ${m.role==="user"?"align-items-end":"align-items-start"}">\n                <div class="small fw-bold text-muted mb-1 mx-2" style="font-size: 0.7rem;">${m.role==="user"?"CLIENT":"LEXIFLOW AI"}</div>\n                <div class="p-3 rounded-4 shadow-sm ${m.role==="user"?"bg-primary text-white":"bg-white border text-dark"}" style="max-width: 85%; border-radius: 15px !important;">\n                    ${m.content}\n                </div>\n                <div class="text-muted mt-1 mx-2" style="font-size: 0.65rem;">${new Date(m.time).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}</div>\n            </div>\n        `).join("");document.getElementById("modal-docs").innerHTML=lead.documents.map(d=>`\n            <div class="card mb-2 border-0 bg-light p-2">\n                <div class="d-flex justify-content-between align-items-center">\n                    <div class="d-flex align-items-center">\n                        <i class="bi ${d.filename.toLowerCase().endsWith(".pdf")?"bi-file-earmark-pdf-fill text-danger":"bi-file-earmark-image-fill text-primary"} fs-4 me-2"></i>\n                        <div><div class="small fw-bold text-dark">${d.filename}</div><div class="text-muted small">${d.analysis?d.analysis.document_type:"Document"}</div></div>\n                    </div>\n                    <button class="btn btn-sm btn-outline-secondary" onclick="alert('In production, this opens the file.')">View</button>\n                </div>\n                ${d.analysis?`\n                    <div class="mt-2 p-2 bg-white rounded border small">\n                        <div class="fw-bold text-primary mb-1">Extracted Data:</div>\n                        ${Object.entries(d.analysis.extracted_fields).map(([k,v])=>`<div><strong>${k}:</strong> ${v}</div>`).join("")}\n                        <div class="text-muted mt-1 italic">${d.analysis.summary||""}</div>\n                    </div>\n                `:""}\n            </div>\n        `).join("")||'<div class="text-center py-3 text-muted">No documents uploaded.</div>';renderModalInvoices(lead.invoices);const esignBadge=document.getElementById("esign-status-badge");if(lead.esign_status&&lead.esign_status!=="Not Sent"){document.getElementById("esign-status-container").classList.remove("d-none");esignBadge.innerText=lead.esign_status;esignBadge.className=`badge ${lead.esign_status==="Signed"?"bg-success":"bg-info"}`}else{document.getElementById("esign-status-container").classList.add("d-none")}const syncBadge=document.getElementById("sync-status-badge");if(lead.sync_status&&lead.sync_status!=="Not Synced"){document.getElementById("sync-status-container").classList.remove("d-none");syncBadge.innerText=lead.sync_status;syncBadge.className=`badge ${getSyncBadge(lead.sync_status)}`;document.getElementById("external-id-text").innerText=lead.external_crm_id?`(ID: ${lead.external_crm_id})`:""}else{document.getElementById("sync-status-container").classList.add("d-none")}new bootstrap.Modal(document.getElementById("leadModal")).show()}catch(error){console.error("Error viewing lead:",error)}}function renderModalInvoices(invoices){document.getElementById("modal-invoices").innerHTML=invoices.map(i=>`\n        <li class="list-group-item d-flex justify-content-between align-items-center bg-light border-0 mb-1 rounded">\n            <div><div class="fw-bold">${getCurrencySymbol(i.currency)}${i.amount.toFixed(2)}</div><div class="text-muted small">${new Date(i.date).toLocaleDateString()}</div></div>\n            <span class="badge ${i.status==="Paid"?"bg-success":"bg-warning"}">${i.status}</span>\n        </li>\n    `).join("")||'<div class="text-center py-2 text-muted small">No payment requests yet.</div>'}function getCurrencySymbol(curr){return curr==="EUR"?"€":"$"}async function loadInvoices(){try{const response=await fetch(API_BASE+"/billing/invoices");const invoices=await response.json();const table=document.getElementById("invoices-table");table.innerHTML=invoices.map(inv=>`\n            <tr>\n                <td class="ps-4">#${inv.id}</td>\n                <td>Lead #${inv.lead_id}</td>\n                <td class="fw-bold">${getCurrencySymbol(inv.currency)}${inv.amount.toFixed(2)}</td>\n                <td><span class="badge ${inv.status==="Paid"?"bg-success":"bg-warning"}">${inv.status}</span></td>\n                <td>${new Date(inv.created_at).toLocaleDateString()}</td>\n                <td class="text-end pe-4">\n                    ${inv.status==="Pending"?`<button class="btn btn-sm btn-outline-success rounded-pill px-3" onclick="syncLawPay(${inv.id})">Sync LawPay</button>`:`<button class="btn btn-sm btn-light disabled rounded-pill px-3">Completed</button>`}\n                </td>\n            </tr>\n        `).join("")||'<tr><td colspan="6" class="text-center py-4">No invoices found.</td></tr>'}catch(e){console.error("Error loading invoices",e)}}async function syncLawPay(id){try{const response=await fetch(API_BASE+`/billing/sync/lawpay/${id}`,{method:"POST"});const result=await response.json();alert(result.message);loadInvoices()}catch(e){console.error("Sync failed",e)}}async function requestPayment(){const leadId=document.getElementById("modal-lead-id").value;const amount=document.getElementById("request-amount").value;const currency=document.getElementById("request-currency").value;if(!amount)return alert("Please enter an amount");const formData=new FormData;formData.append("lead_id",leadId);formData.append("amount",amount);formData.append("currency",currency);formData.append("description","Retainer Request");try{const response=await fetch(API_BASE+"/billing/invoices",{method:"POST",body:formData});if(response.ok){alert("Payment request sent!");document.getElementById("request-amount").value="";const leadResponse=await fetch(API_BASE+`/leads/${leadId}`);const lead=await leadResponse.json();renderModalInvoices(lead.invoices)}}catch(e){console.error("Request failed",e)}}async function sendRetainer(){const leadId=document.getElementById("modal-lead-id").value;try{const response=await fetch(API_BASE+`/esign/send/${leadId}`,{method:"POST"});if(response.ok){const result=await response.json();alert(`Retainer sent! Request ID: ${result.signature_request_id}`);const leadResponse=await fetch(API_BASE+`/leads/${leadId}`);const lead=await leadResponse.json();const esignContainer=document.getElementById("esign-status-container");const esignBadge=document.getElementById("esign-status-badge");esignContainer.classList.remove("d-none");esignBadge.innerText=lead.esign_status;esignBadge.className="badge bg-info"}}catch(e){console.error("eSign Request failed",e)}}async function loadAuditLogs(){try{const response=await fetch(API_BASE+"/audit-logs");const logs=await response.json();document.getElementById("audit-logs-table").innerHTML=logs.map(log=>`\n            <tr>\n                <td class="ps-3"><span class="badge bg-light text-dark border">${log.action}</span></td>\n                <td>${log.lead_id||"-"}</td>\n                <td class="text-wrap" style="max-width: 300px;">${log.details||""}</td>\n                <td class="text-muted">${new Date(log.timestamp).toLocaleString()}</td>\n            </tr>\n        `).join("")}catch(e){console.error("Error loading audit logs",e)}}async function exportLeadPrivacy(){const leadId=document.getElementById("privacy-lead-id").value;if(!leadId)return alert("Please enter a Lead ID");try{const response=await fetch(API_BASE+`/leads/${leadId}/export`);if(!response.ok)throw new Error("Lead not found");const data=await response.json();const blob=new Blob([JSON.stringify(data,null,2)],{type:"application/json"});const url=window.URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=`lead_${leadId}_data.json`;a.click()}catch(e){alert(e.message)}}async function deleteLeadPrivacy(){const leadId=document.getElementById("privacy-lead-id").value;if(!leadId)return alert("Please enter a Lead ID");if(!confirm("Permanently delete all data for this lead?"))return;try{const response=await fetch(API_BASE+`/leads/${leadId}`,{method:"DELETE"});const result=await response.json();alert(result.message);loadLeads();loadAuditLogs()}catch(e){alert("Error deleting lead")}}window.showSection=function(section){["leads","forms","billing","settings"].forEach(s=>document.getElementById("section-"+s).classList.add("d-none"));document.querySelectorAll(".nav-link").forEach(link=>link.classList.remove("active"));document.getElementById("section-"+section).classList.remove("d-none");document.getElementById("nav-"+section).classList.add("active");if(section==="leads")loadLeads();if(section==="billing")loadInvoices();if(section==="settings"){loadAuditLogs();loadKB();document.getElementById("webhook-url").value=API_BASE+"/reception/webhook"}};async function loadKB(){try{const response=await fetch(API_BASE+"/knowledge-base");const kb=await response.json();document.getElementById("kb-list").innerHTML=kb.map(item=>`\n            <div class="list-group-item">\n                <div class="d-flex justify-content-between align-items-start">\n                    <div class="fw-bold">${item.title}</div>\n                    <button class="btn btn-sm btn-link text-danger p-0" onclick="deleteKB(${item.id})"><i class="bi bi-trash"></i></button>\n                </div>\n                <div class="small text-muted mt-1">${item.content}</div>\n                <div class="text-muted italic mt-1" style="font-size: 0.65rem;">Added ${new Date(item.created_at).toLocaleDateString()}</div>\n            </div>\n        `).join("")||'<div class="p-4 text-center text-muted">No context entries yet.</div>'}catch(e){console.error("Error loading KB",e)}}async function saveKB(){const title=document.getElementById("kb-title").value;const content=document.getElementById("kb-content").value;if(!title||!content)return alert("Title and content required");const formData=new FormData;formData.append("title",title);formData.append("content",content);try{const response=await fetch(API_BASE+"/knowledge-base",{method:"POST",body:formData});if(response.ok){alert("Knowledge Base entry added!");document.getElementById("kb-title").value="";document.getElementById("kb-content").value="";loadKB()}}catch(e){console.error("KB Save failed",e)}}async function deleteKB(id){if(!confirm("Remove this entry from AI context?"))return;try{const response=await fetch(API_BASE+`/knowledge-base/${id}`,{method:"DELETE"});if(response.ok){alert("Entry removed.");loadKB()}}catch(e){console.error("Delete failed",e)}}function copyWebhook(){const el=document.getElementById("webhook-url");el.select();document.execCommand("copy");alert("Webhook URL copied to clipboard!")}loadLeads();setInterval(()=>{if(!document.getElementById("filter-status").value&&!document.getElementById("filter-score").value&&!document.getElementById("search-input").value)loadLeads()},3e4);async function syncToSystem(leadId,system){const btn=event?event.target.closest("button"):null;const originalHtml=btn?btn.innerHTML:"";if(btn)btn.innerHTML='<span class="spinner-border spinner-border-sm me-1"></span>Syncing...';try{const response=await fetch(API_BASE+`/sync/${system}/${leadId}`,{method:"POST"});const result=await response.json();if(result.status==="success"){loadLeads();document.getElementById("sync-system-name").innerText=`Target System: ${system.charAt(0).toUpperCase()+system.slice(1)} ${system==="clio"?"Grow":""}`;document.getElementById("sync-payload-display").innerText=JSON.stringify(result.payload_sent,null,2);const syncModal=new bootstrap.Modal(document.getElementById("syncResultModal"));syncModal.show();if(btn){btn.innerHTML='<i class="bi bi-check2-all me-1"></i>Synced';btn.className=btn.className.replace("btn-primary","btn-success")}}else{alert(`Sync failed: ${result.message}`);if(btn)btn.innerHTML=originalHtml}}catch(e){console.error("Sync failed",e);alert("Sync failed. See console for details.");if(btn)btn.innerHTML=originalHtml}}function copySyncPayload(){const text=document.getElementById("sync-payload-display").innerText;navigator.clipboard.writeText(text).then(()=>{alert("Payload JSON copied to clipboard!")})}async function exportClioCSV(){const leadId=document.getElementById("modal-lead-id").value;window.location.href=`${API_BASE}/leads/${leadId}/export/clio`}